    lines.push("# AI Fix Prompts for Cursor");
    lines.push("");
    lines.push(
      `Generated ${prompts.length} fix prompts. Use Cursor AI to apply these fixes.`
    );
    lines.push("");
    for (let i2 = 0; i2 < prompts.length; i2++) {
      const prompt = prompts[i2];
      lines.push(`## Fix ${i2 + 1}: ${prompt.finding} (${prompt.severity})`);
      lines.push("");
      lines.push(`**File:** \`${prompt.file}:${prompt.line}\``);
      lines.push("");
      lines.push("**Prompt for Cursor:**");
      lines.push("```");
      lines.push(prompt.fixPrompt);
      lines.push("```");
      lines.push("");
      lines.push(
        "**To apply:** Open file in Cursor, position cursor at the line, and use Cmd+K with the prompt above."
      );
      lines.push("");
      lines.push("---");
      lines.push("");
    }
