    lines.push("=".repeat(50));
    lines.push("");
    lines.push(`Total prompts: ${prompts.length}`);
    lines.push("");
    for (let i2 = 0; i2 < prompts.length; i2++) {
      const prompt = prompts[i2];
      lines.push(`[${i2 + 1}] ${prompt.finding} (${prompt.severity})`);
      lines.push(`    Location: ${prompt.file}:${prompt.line}`);
      if (prompt.category) {
        lines.push(`    Category: ${prompt.category}`);
      }
      lines.push("");
      lines.push("    Fix prompt:");
      const promptLines = prompt.fixPrompt.split("\n");
      for (const line of promptLines) {
        lines.push(`    ${line}`);
      }
      lines.push("");
      lines.push("-".repeat(50));
      lines.push("");
    }
